def is_inside(a, b, c, d):
    return a <= c <= b


def intersect(a, b, c, d):
    return is_inside(a, b, c, d) or is_inside(a, b, d, c)


n = int(input())
x1, x2 = map(int, input().split())

k = []
b = []

for i in range(n):
    ki, bi = map(int, input().split())
    k.append(ki)
    b.append(bi)

for i in range(n - 1):
    for j in range(i + 1, n):
        if k[i] == k[j]:
            continue
        x = (b[j] - b[i]) / (k[i] - k[j])
        y = k[i] * x + b[i]
        if intersect(x1, x2, x, y):
            print('YES')
            exit()
print('NO')
